// Capture startup failure
@Component
public class StartupFailureListener
        implements ApplicationListener<ApplicationFailedEvent> {
    private static final Logger log =
        LoggerFactory.getLogger(StartupFailureListener.class);

    @Override
    public void onApplicationEvent(ApplicationFailedEvent event) {
        Throwable ex = event.getException();
        log.error("Application failed to start", ex);
        // Walk cause chain
        Throwable cause = ex.getCause();
        while (cause != null) {
            log.error("Caused by: {}", cause.getMessage());
            cause = cause.getCause();
        }
    }
}

