// Detect JVM deadlock programmatically
@Scheduled(fixedDelay = 30000)
public void checkForDeadlocks() {
    ThreadMXBean bean = ManagementFactory.getThreadMXBean();
    long[] deadlockedThreads = bean.findDeadlockedThreads();
    if (deadlockedThreads != null) {
        ThreadInfo[] infos = bean.getThreadInfo(deadlockedThreads, true, true);
        for (ThreadInfo info : infos) {
            log.error("DEADLOCK detected: thread={} waiting for={}",
                info.getThreadName(), info.getLockName());
        }
        // Alert ops team
        alertService.sendDeadlockAlert(infos);
    }
}

// Avoid lock ordering deadlock
// WRONG: Thread 1 locks A then B, Thread 2 locks B then A
public void transfer(Account from, Account to, BigDecimal amount) {
    synchronized(from) {       // Thread 1 holds from
        synchronized(to) {     // Thread 2 holds to — DEADLOCK
            from.debit(amount);
            to.credit(amount);
        }
    }
}

// CORRECT: always lock in consistent order (by ID)
public void transfer(Account from, Account to, BigDecimal amount) {
    Account first  = from.getId() < to.getId() ? from : to;
    Account second = from.getId() < to.getId() ? to : from;
    synchronized(first) {
        synchronized(second) {
            from.debit(amount);
            to.credit(amount);
        }
    }
}

