// WITHOUT happens-before — BROKEN
class BrokenVisibility {
    private boolean ready = false;
    private int data = 0;

    // Thread 1 writes
    public void writer() {
        data = 42;
        ready = true;  // May be reordered BEFORE data=42!
    }

    // Thread 2 reads
    public void reader() {
        while (!ready) {} // May spin forever OR see ready=true, data=0
        System.out.println(data); // May print 0!
    }
}

// WITH volatile — establishes happens-before
class CorrectVisibility {
    private volatile boolean ready = false;
    private int data = 0;

    public void writer() {
        data = 42;      // HB: happens before volatile write
        ready = true;  // Volatile write — establishes HB
    }

    public void reader() {
        while (!ready) {} // Volatile read — sees everything before write
        System.out.println(data); // GUARANTEED to print 42
    }
}

