// Safe non-blocking increment (CAS loop)
public static int safeIncrement(AtomicInteger counter) {
    while (true) {
        int current = counter.get();
        int next = current + 1;
        if (counter.compareAndSet(current, next)) {
            return next; // Success!
        }
