// Outbox Pattern — atomic order creation + event publishing
@Service
@Transactional
public class OrderService {

    public Order createOrder(CreateOrderRequest req) {
        // Step 1: Create order in orders DB
        Order order = orderRepo.save(new Order(req));

        // Step 2: Write to outbox IN SAME TRANSACTION
        OutboxEvent event = new OutboxEvent(
            UUID.randomUUID().toString(),
            "ORDER_CREATED",
            "orders",
            order.getId().toString(),
            objectMapper.writeValueAsString(order),
            Instant.now());
        outboxRepo.save(event);

        // DB commits both — atomic!
        return order;
    }
}

// Separate process reads outbox and publishes to Kafka
@Scheduled(fixedDelay = 100)
@Transactional
public void publishOutboxEvents() {
    List<OutboxEvent> events = outboxRepo.findUnpublished();
    events.forEach(event -> {
        kafkaTemplate.send(event.getTopic(), event.getAggregateId(),
            event.getPayload());
        event.setPublished(true);
        outboxRepo.save(event);
    });
