@Service
public class PaymentService {

    @Autowired private PaymentRepository paymentRepo;
    @Autowired private StripeGateway stripeGateway;

    public PaymentResponse processPayment(PaymentRequest req) {
        // 1. Idempotency check
        Optional<Payment> existing =
            paymentRepo.findByIdempotencyKey(req.getIdempotencyKey());
        if (existing.isPresent()) {
            return PaymentResponse.from(existing.get());
        }

        // 2. Persist intent BEFORE calling gateway
        Payment payment = paymentRepo.save(Payment.builder()
            .orderId(req.getOrderId())
            .amount(req.getAmount())
            .idempotencyKey(req.getIdempotencyKey())
            .status(PaymentStatus.PENDING)
            .build());

        // 3. Call gateway OUTSIDE @Transactional
        try {
            StripeCharge charge = stripeGateway.charge(
                req.getToken(),
                req.getAmount(),
                req.getCurrency(),
                payment.getId().toString()); // our ID as metadata

            // 4. Update status
            payment.setStatus(PaymentStatus.SUCCESS);
            payment.setGatewayTransactionId(charge.getId());
            paymentRepo.save(payment);
            return PaymentResponse.success(payment);

        } catch (StripeCardException ex) {
            // Permanent failure — card declined, insufficient funds
            payment.setStatus(PaymentStatus.FAILED);
            payment.setFailureReason(ex.getMessage());
            paymentRepo.save(payment);
            throw new PaymentDeclinedException(ex.getMessage());
        } catch (StripeApiException ex) {
            // Transient — retry later
            payment.setStatus(PaymentStatus.PENDING_RETRY);
            paymentRepo.save(payment);
            throw new PaymentRetryableException("Gateway unavailable");
        }
    }

    // Webhook handler for async confirmation
    @PostMapping("/webhooks/stripe")
    public ResponseEntity<Void> handleWebhook(
            @RequestBody String payload,
            @RequestHeader("Stripe-Signature") String sig) {
        Event event = stripeGateway.verifyWebhook(payload, sig);
        if ("payment_intent.succeeded".equals(event.getType())) {
            String paymentId = event.getData().getMetadata().get("our_id");
            paymentRepo.findById(Long.parseLong(paymentId))
                .ifPresent(p -> {
                    p.setStatus(PaymentStatus.SUCCESS);
                    paymentRepo.save(p);
                });
        }
        return ResponseEntity.ok().build();
    }
}

