public class StartsWith1 {
    public static void main(String[] args) {
        List<Integer> numbers = Arrays.asList(11, 18, 20, 24, 85, 66, 13);

        // Filter numbers starting with '1'
        List<Integer> result = numbers.stream()
            .filter(n -> String.valueOf(n).startsWith("1"))
            .collect(Collectors.toList());

        System.out.println(result); // [11, 18, 13]

        // Generic version — find numbers starting with any digit
        String prefix = "1";
        List<Integer> generic = numbers.stream()
            .filter(n -> String.valueOf(Math.abs(n)).startsWith(prefix))
            .collect(Collectors.toList());

        // Print without collecting
        System.out.println("Numbers starting with 1:");
        numbers.stream()
            .filter(n -> String.valueOf(n).startsWith("1"))
            .forEach(System.out::println);
        // Output: 11, 18, 13

        // Count how many start with 1
        long count = numbers.stream()
            .filter(n -> String.valueOf(n).startsWith("1"))
            .count();
        System.out.println("Count: " + count); // 3
    }
}

