public class EmployeeStats {
    public static void main(String[] args) {
        List<Employee> employees = Arrays.asList(
            new Employee(1, "Alice", 30, "Female", 80000),
            new Employee(2, "Bob",   25, "Male",   60000),
            new Employee(3, "Carol", 35, "Female", 90000),
            new Employee(4, "Dave",  28, "Male",   70000),
            new Employee(5, "Eve",   32, "Female", 85000)
        );

        // a) Count by gender
        Map<String, Long> countByGender = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::getGender,
                Collectors.counting()));
        System.out.println("Count by gender: " + countByGender);
        // {Female=3, Male=2}

        // b) Average salary by gender
        Map<String, Double> avgSalaryByGender = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::getGender,
                Collectors.averagingDouble(Employee::getSalary)));
        System.out.println("Avg salary by gender: " + avgSalaryByGender);
        // {Female=85000.0, Male=65000.0}

