// 2. WebClient — reactive non-blocking REST
@Service
public class PaymentClient {
    private final WebClient webClient;

    public Mono<PaymentResult> charge(PaymentRequest req) {
        return webClient.post()
            .uri("/payments/charge")
            .bodyValue(req)
            .retrieve()
            .onStatus(HttpStatus::is5xxServerError,
                r -> Mono.error(new PaymentServiceException()))
            .bodyToMono(PaymentResult.class)
            .timeout(Duration.ofSeconds(5));
    }
}

// 3. Kafka — async event-driven
// Producer
@Service
public class OrderService {
    @Autowired private KafkaTemplate<String, OrderEvent> kafka;

    public Order createOrder(CreateOrderRequest req) {
        Order order = orderRepo.save(new Order(req));
        kafka.send("order-events",
            order.getId().toString(),
            new OrderCreatedEvent(order));
        return order; // Returns immediately, doesn't wait
    }
}

