// Custom interface + implementation pattern
public interface UserRepositoryCustom {
    List<User> findUsersWithComplexCriteria(
        String dept, int minAge, BigDecimal minSalary);
}

public class UserRepositoryImpl implements UserRepositoryCustom {
    @PersistenceContext EntityManager em;

    @Override
    public List<User> findUsersWithComplexCriteria(
            String dept, int minAge, BigDecimal minSalary) {
        // Criteria API query
        CriteriaBuilder cb = em.getCriteriaBuilder();
        CriteriaQuery<User> query = cb.createQuery(User.class);
        Root<User> root = query.from(User.class);
        query.where(cb.and(
            cb.equal(root.get("department"), dept),
            cb.greaterThan(root.get("age"), minAge),
            cb.greaterThan(root.get("salary"), minSalary)));
        return em.createQuery(query).getResultList();
    }
}

// Combined repository
public interface UserRepository
        extends JpaRepository<User, Long>,
                JpaSpecificationExecutor<User>,
                UserRepositoryCustom {
    // Has all methods from all three
}

