// Programmatically access any property
@Component
public class ConfigPrinter implements ApplicationRunner {
    @Autowired
    private ConfigurableEnvironment env;

    @Override
    public void run(ApplicationArguments args) {
        // Print all property sources and their precedence
        env.getPropertySources().stream()
            .filter(ps -> ps instanceof EnumerablePropertySource)
            .map(ps -> (EnumerablePropertySource<?>) ps)
            .forEach(ps -> {
                System.out.println("Source: " + ps.getName());
                Arrays.stream(ps.getPropertyNames())
                    .forEach(key -> System.out.printf(
                        "  %s = %s%n", key, ps.getProperty(key)));
            });

        // Get specific property
        String port = env.getProperty("server.port");
        System.out.println("Effective port: " + port);
    }
}

