// refresh() is called from SpringApplication.run()
// Inside AbstractApplicationContext:

public void refresh() {
    // Step 1
    prepareRefresh();
    // Step 2
    ConfigurableListableBeanFactory beanFactory =
        obtainFreshBeanFactory();
    // Step 3
    prepareBeanFactory(beanFactory);
    // Step 4
    postProcessBeanFactory(beanFactory);
    // Step 5 — ConfigurationClassPostProcessor runs here
    // Processes ALL @Configuration, @ComponentScan, @Import
    invokeBeanFactoryPostProcessors(beanFactory);
    // Step 6 — register but don't instantiate BeanPostProcessors
    registerBeanPostProcessors(beanFactory);
    // Steps 7-8
    initMessageSource();
    initApplicationEventMulticaster();
    // Step 9 — Tomcat starts here!
    onRefresh(); // -> createWebServer() in web context
    // Step 10
    registerListeners();
    // Step 11 — ALL singleton beans instantiated
    // @PostConstruct runs here
    finishBeanFactoryInitialization(beanFactory);
    // Step 12 — ContextRefreshedEvent fired
    finishRefresh();
}

