// Check active profiles at runtime
@Component
public class ProfileLogger implements ApplicationRunner {
    @Autowired Environment env;

    public void run(ApplicationArguments a) {
        String[] profiles = env.getActiveProfiles();
        log.info("Active profiles: {}",
            Arrays.toString(profiles));
        boolean isProd = env.acceptsProfiles(
            Profiles.of("prod"));
        if (isProd) log.warn("Running in PRODUCTION!");
    }
}

